import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Replayable CPU viewport center.
///
/// The controller normally provides finite pan coordinates, but CPU fallback
/// code also accepts replayed/isolate scalar requests. Non-finite pan samples
/// must not poison every formula coordinate with NaN/Infinity, so they adopt
/// the origin instead.
final class CpuViewportCenter {
  const CpuViewportCenter({required this.x, required this.y});

  final double x;
  final double y;

  factory CpuViewportCenter.fromScalars({
    required double panX,
    required double panY,
  }) {
    return CpuViewportCenter(
      x: normalizeCoordinate(panX),
      y: normalizeCoordinate(panY),
    );
  }

  static double normalizeCoordinate(double value) {
    return value.isFinite ? value : 0.0;
  }
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  }) : this._(
          center: CpuViewportCenter.fromScalars(panX: panX, panY: panY),
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping._({
    required CpuViewportCenter center,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = center.x,
        centerY = center.y,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        final viewport = CpuViewportMapping(
          viewPan: Vector2.zero(),
          viewZoom: zoom,
          width: 2,
          height: 2,
        );

        expect(viewport.scale, 1.5, reason: 'zoom=$zoom');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, -0.75),
          reason: 'zoom=$zoom',
        );
      }
    });

    test('invalid pan falls back to the replayable origin center', () {
      for (final pan in [
        Vector2(double.nan, 0.25),
        Vector2(double.infinity, double.negativeInfinity),
      ]) {
        final center = CpuViewportCenter.fromScalars(
          panX: pan.x,
          panY: pan.y,
        );
        final viewport = CpuViewportMapping(
          viewPan: pan,
          viewZoom: 1.0,
          width: 2,
          height: 2,
        );
        final expectedY = pan.y.isFinite ? pan.y : 0.0;

        expect(center.x, 0.0, reason: 'pan=$pan');
        expect(center.y, expectedY, reason: 'pan=$pan');
        expect(viewport.centerX, center.x, reason: 'pan=$pan');
        expect(viewport.centerY, center.y, reason: 'pan=$pan');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, expectedY - 0.75),
          reason: 'pan=$pan',
        );
      }
    });

    test('invalid viewport dimensions fall back to square aspect', () {
      expect(
        CpuViewportDimensions.fromSize(width: 0, height: 2).aspect,
        1.0,
      );
      expect(
        CpuViewportDimensions.fromSize(width: 2, height: -1).aspect,
        1.0,
      );

      final zeroWidthViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 0,
        height: 2,
      );
      final negativeHeightViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: -1,
      );

      expect(zeroWidthViewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
      expect(
        negativeHeightViewport.coordinate(nx: 0.5, ny: -0.5),
        (0.75, -0.75),
      );
    });

    test('iteration buffer shares CPU render dimension validation', () async {
      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 0,
          height: 2,
        ),
        throwsArgumentError,
      );

      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 2,
          height: -1,
        ),
        throwsArgumentError,
      );
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('isolate sample mapping shares invalid pan normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: double.nan,
        panY: double.infinity,
        zoom: 1.0,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('anti-aliasing grid makes non-square sample counts replayable', () {
      expect(CpuSampleGrid.fromRequestedCount(-1).samplesPerAxis, 1);
      expect(CpuSampleGrid.fromRequestedCount(1).totalSamples, 1);
      expect(CpuSampleGrid.fromRequestedCount(4).totalSamples, 4);
      expect(CpuSampleGrid.fromRequestedCount(8).samplesPerAxis, 3);
      expect(CpuSampleGrid.fromRequestedCount(8).totalSamples, 9);
    });

    test('anti-aliasing grid never drops requested multisample candidates', () {
      for (final requestedCount in [2, 3, 5, 6, 7, 8]) {
        final grid = CpuSampleGrid.fromRequestedCount(requestedCount);

        expect(
          grid.totalSamples,
          greaterThanOrEqualTo(requestedCount),
          reason: 'requestedCount=$requestedCount',
        );
        expect(grid.requestedCount, requestedCount);
        expect(grid.wasRoundedUp, isTrue);
      }
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

export 'cpu_viewport_mapping.dart'
    show CpuRenderDimensions, CpuRenderRect, CpuRenderSamplePoint;

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = renderCpuRectRgba(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

final class CpuViewportCoordinate {
  const CpuViewportCoordinate(this.x, this.y);

  final double x;
  final double y;
}

/// Maps a pixel sample to the CPU fractal plane.
///
/// [sampleOffsetX] and [sampleOffsetY] are normalized offsets within the pixel
/// (0.5 means pixel center). Dividing by the full dimensions keeps one-pixel
/// renders centered on pan and keeps opposite edge pixel centers symmetric.
CpuViewportCoordinate cpuViewportCoordinateForSample({
  required double panX,
  required double panY,
  required double zoom,
  required int fullWidth,
  required int fullHeight,
  required int x,
  required int y,
  required double sampleOffsetX,
  required double sampleOffsetY,
}) {
  CpuRenderSamplePoint(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x: x,
    y: y,
  ).validate();

  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );
  final nx = viewport.normalizedSampleOffset(
    pixel: x,
    extent: fullWidth,
    sampleOffset: sampleOffsetX,
  );
  final ny = viewport.normalizedSampleOffset(
    pixel: y,
    extent: fullHeight,
    sampleOffset: sampleOffsetY,
  );
  final coordinate = viewport.coordinate(nx: nx, ny: ny);

  return CpuViewportCoordinate(coordinate.$1, coordinate.$2);
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = renderCpuRectRgba(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

/// Renders one CPU RGBA tile from an explicit full-viewport rectangle.
///
/// This pure raster helper is shared by direct, full-frame isolate, and tile
/// isolate render paths so they fail on the same invalid dimensions and sample
/// the same viewport coordinates.
Uint8List renderCpuRectRgba({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'dart:math' as math;

/// Replayable CPU render dimensions for preview/refine/slow-mode passes.
///
/// The CPU renderer uses reduced preview passes while gestures are active and a
/// high-resolution slow-mode pass after refinement. Keeping those dimensions in
/// a pure value object exposes the magic floors/caps and makes tiny viewport
/// edge cases testable without spinning up timers or isolates.
final class CpuRenderResolution {
  const CpuRenderResolution({required this.width, required this.height});

  static const int minInteractiveDimension = 200;
  static const int minSlowModeWidth = 400;
  static const int minSlowModeHeight = 400;
  static const int maxSlowModeWidth = 2160;
  static const int maxSlowModeHeight = 3840;

  final int width;
  final int height;

  factory CpuRenderResolution.forPass({
    required int targetWidth,
    required int targetHeight,
    required double resolutionScale,
  }) {
    return CpuRenderResolution(
      width: _interactiveDimension(
        targetDimension: targetWidth,
        resolutionScale: resolutionScale,
      ),
      height: _interactiveDimension(
        targetDimension: targetHeight,
        resolutionScale: resolutionScale,
      ),
    );
  }

  factory CpuRenderResolution.forSlowMode({
    required int targetWidth,
    required int targetHeight,
  }) {
    return CpuRenderResolution(
      width:
          (targetWidth * 2).clamp(minSlowModeWidth, maxSlowModeWidth).toInt(),
      height: (targetHeight * 2)
          .clamp(minSlowModeHeight, maxSlowModeHeight)
          .toInt(),
    );
  }

  static int _interactiveDimension({
    required int targetDimension,
    required double resolutionScale,
  }) {
    if (!resolutionScale.isFinite || resolutionScale >= 1.0) {
      return targetDimension;
    }
    if (targetDimension <= 0) return targetDimension;

    final lowerBound = math.min(minInteractiveDimension, targetDimension);
    return (targetDimension * resolutionScale)
        .round()
        .clamp(lowerBound, targetDimension)
        .toInt();
  }
}

